import { Injectable } from '@nestjs/common';
@Injectable()
export class TransactionsService {
  private txs: any[] = [];
  private idc = 1;
  create(p: any) {
    const ts = new Date().getTime();
    const tx = { id: this.idc++, ...p, createdAt: ts, updatedAt: ts };
    this.txs.push(tx);
    return tx;
  }
  update(id: number, p: any) {
    const tx = this.txs.find(x => x.id === id);
    Object.assign(tx, p);
    tx.updatedAt = new Date().getTime();
    return tx;
  }
}

