import { Injectable, NotFoundException } from '@nestjs/common';
@Injectable()
export class LaboratoriesService {
  private labs = [{ id: 1, name: 'Main Lab' }];
  validate(id: number) { const l = this.labs.find(x => x.id === id); if(!l) throw new NotFoundException(); return l; }
}

import { Module } from '@nestjs/common';
