@Module({ providers: [LaboratoriesService], exports: [LaboratoriesService] })
export class LaboratoriesModule {}

import { Injectable } from '@nestjs/common';
import { LaboratoriesService } from '../laboratories/laboratories.service';
@Injectable()
export class DevicesService {
  private devs = [];
  constructor(private labs: LaboratoriesService) {}
  create(p: { name: string, labId: number }) {
    this.labs.validate(p.labId);
    const ts = new Date().getTime();
    const d = { id: 1, name: p.name.trim().toLowerCase(), labId: p.labId, createdAt: ts, updatedAt: ts };
    this.devs.push(d);
    return d;
  }
}

